import {
	DynamoDBClient,
	GetItemCommand,
} from '@aws-sdk/client-dynamodb';
import { getTenantId, getTenantTableNames, createResponse } from 'tenant-utils';

const dynamodb = new DynamoDBClient({ region: process.env.AWS_REGION });

const fetchConfig = async (configType, tableNames, tenantId) => {
	const result = await dynamodb.send(new GetItemCommand({
		TableName: tableNames.configTable,
		Key: {
			id: { S: tenantId },
			configtype: { S: configType },
		},
	}));

	if (!result.Item) {
		throw new Error(`No ${configType} found for tenant ${tenantId}`);
	}

	return JSON.parse(result.Item.value.S);
};

export const handler = async (event) => {
	let tenantId = null;

	try {
		// Only resolve tenantId and table names — feconfig does NOT need
		// userPoolId, appClientId, appSecret, or any Cognito lookups.
		// This skips the expensive DynamoDB Query in getTenantInfoFromDB()
		// and any potential Cognito DescribeUserPoolClient call.
		tenantId = await getTenantId(event);
		const tableNames = getTenantTableNames(tenantId);

		const [FeConfig, BrandingConfig, LegalConfig] = await Promise.all([
			fetchConfig('amfaConfigs', tableNames, tenantId),
			fetchConfig('amfaBrandings', tableNames, tenantId),
			fetchConfig('amfaLegals', tableNames, tenantId),
		]);

		return createResponse(200, {
			...FeConfig,
			recaptcha_key: FeConfig?.recaptcha_key || '',
			branding: {
				...BrandingConfig,
			},
			legal: {
				...LegalConfig,
			}
		}, tenantId);

	} catch (e) {
		console.error(`[Tenant: ${tenantId || 'unknown'}] feconfig error:`, e.message);
		return createResponse(500, { type: 'exception', message: 'Service Error' }, tenantId);
	}
};
